#!/usr/bin/env python3
import sys, re, math

def safe_eval(expr: str) -> float:
    # Tokenize: numbers, operators, parentheses
    # Allow whitespace.
    tokens = re.findall(r"\d+(?:\.\d+)?|[()+\-*/]", expr.replace(' ', ''))
    if not tokens:
        raise ValueError('empty')

    # Shunting-yard to RPN
    prec = {'+':1,'-':1,'*':2,'/':2}
    assoc = {'+':'L','-':'L','*':'L','/':'L'}

    output = []
    ops = []

    def is_number(t):
        return re.fullmatch(r"\d+(?:\.\d+)?", t) is not None

    prev = None
    for t in tokens:
        if is_number(t):
            output.append(float(t))
            prev = 'num'
        elif t in '+-*/':
            # handle unary minus/plus by inserting 0
            if prev in (None, 'op', '('):
                if t in '+-':
                    output.append(0.0)
                else:
                    raise ValueError('bad unary')
            while ops and ops[-1] in prec:
                top = ops[-1]
                if (prec[top] > prec[t]) or (prec[top] == prec[t] and assoc[t]=='L'):
                    output.append(ops.pop())
                else:
                    break
            ops.append(t)
            prev = 'op'
        elif t == '(':
            ops.append(t)
            prev = '('
        elif t == ')':
            while ops and ops[-1] != '(':
                output.append(ops.pop())
            if not ops or ops[-1] != '(':
                raise ValueError('mismatched')
            ops.pop()
            prev = ')'
        else:
            raise ValueError('token')

    while ops:
        if ops[-1] in '()':
            raise ValueError('mismatched')
        output.append(ops.pop())

    # Evaluate RPN
    stack = []
    for item in output:
        if isinstance(item, float):
            stack.append(item)
        else:
            b = stack.pop(); a = stack.pop()
            if item == '+': stack.append(a+b)
            elif item == '-': stack.append(a-b)
            elif item == '*': stack.append(a*b)
            elif item == '/': stack.append(a/b)
            else: raise ValueError('op')
    if len(stack)!=1:
        raise ValueError('bad')
    return stack[0]


def main():
    if len(sys.argv) < 2:
        print('usage: calc <expr>', file=sys.stderr)
        return 2
    expr = ' '.join(sys.argv[1:])
    val = safe_eval(expr)
    # Print without trailing .0 when integer
    if abs(val - round(val)) < 1e-12:
        print(int(round(val)))
    else:
        # enough precision
        print(repr(float(val)))

if __name__ == '__main__':
    main()
PY
