# Parse /usr/stock.log: last two columns are stock index and count.
# Determine stock indices where Bob sold (negative count) but never bought (positive count).
log=/usr/stock.log
if [ ! -f "$log" ]; then
  echo "missing" >&2
  exit 1
fi
# Extract columns: assume format: ... <person> <action> <stock_index> <count>
# We'll robustly take last two fields as index and count, and infer action/person from remaining fields.
# Count sold by Bob: action contains 'sell' and person contains 'Bob' (case-insensitive).
# Count bought by Bob: action contains 'buy' and person contains 'Bob'.
awk 'BEGIN{IGNORECASE=1}
{
  idx=$(NF-1); cnt=$NF;
  # Determine if line mentions Bob and buy/sell
  bob=($0 ~ /\bBob\b/);
  buy=($0 ~ /\bbuy\b/);
  sell=($0 ~ /\bsell\b/);
  if(bob && buy){ bought[idx]=1 }
  if(bob && sell){ sold[idx]=1 }
}
END{
  c=0;
  for(i in sold){ if(!(i in bought)) c++ }
  print c
}' "$log""}
